import argparse
import json
import os
import numpy as np
import heapq

from cogniplan_env import ExplorationEnv


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n['coords'])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get('coords', nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) -
                    np.array(nodes[j]['coords'], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    node_to_nb = {}
    for idx, nb in enumerate(neighbors):
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) - np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
            node_to_nb[j] = idx
    return adj, coord_to_idx, r_idx, node_to_nb


def first_step_index(prev, r_idx, target_j, node_to_nb):
    if prev[target_j] is None:
        return None
    cur = target_j
    depth = 0
    max_depth = len(prev) + 5
    while prev[cur] != r_idx and prev[cur] is not None and depth < max_depth:
        cur = prev[cur]
        depth += 1
    if prev[cur] == r_idx and cur in node_to_nb:
        return node_to_nb[cur]
    return None


class SimpleGreedyPlanner:
    def __init__(self, dist_denom=1.0, reverse_penalty=0.0, persist_boost=1.0):
        self.dist_denom = float(dist_denom)
        self.reverse_penalty = float(reverse_penalty)
        self.persist_boost = float(persist_boost)
        self.reset()

    def reset(self):
        self.prev_pos = None
        self.prev_target_coord = None
        self.step_count = 0

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs['robot_pos'], dtype=float)
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        frontiers = obs.get('frontiers', [])

        if not neighbors:
            self.prev_pos = robot_pos
            return None

        adj, coord_to_idx, r_idx, node_to_nb = build_graph(
            nodes, robot_pos, neighbors
        )
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        # Detect backtracking neighbor
        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        prev_target_j = None
        if self.prev_target_coord is not None:
            prev_target_j = coord_to_idx.get(round_coord(self.prev_target_coord))

        candidate_js = [
            j for j in range(N)
            if j in node_to_nb and dist[j] < float('inf')
        ]
        if not candidate_js:
            self.prev_pos = robot_pos
            return self._fallback(neighbors, frontiers, nodes, robot_pos)

        primary = [
            j for j in candidate_js
            if float(nodes[j].get('utility', 0.0)) > 0
        ]
        if not primary:
            primary = candidate_js

        node_scores = {}
        for j in primary:
            utility = float(nodes[j].get('utility', 0.0))
            d = dist[j]
            score = utility / (d + self.dist_denom)
            if prev_target_j is not None and j == prev_target_j:
                score *= self.persist_boost
            node_scores[j] = score

        nb_scores = {}
        for j, score in node_scores.items():
            fs = first_step_index(prev, r_idx, j, node_to_nb)
            if fs is None:
                continue
            if fs not in nb_scores or score > nb_scores[fs]:
                nb_scores[fs] = score

        if not nb_scores:
            self.prev_pos = robot_pos
            return self._fallback(neighbors, frontiers, nodes, robot_pos)

        for idx in nb_scores:
            if reverse_idx is not None and idx == reverse_idx:
                nb_scores[idx] *= (1.0 - self.reverse_penalty)

        best_idx = max(nb_scores, key=nb_scores.get)
        best_j = None
        for j, score in node_scores.items():
            fs = first_step_index(prev, r_idx, j, node_to_nb)
            if fs == best_idx and abs(score - nb_scores[best_idx]) < 1e-9:
                best_j = j
                break
        if best_j is None:
            best_j = list(node_scores.keys())[0]

        self.prev_target_coord = tuple(nodes[best_j]['coords'])
        self.prev_pos = robot_pos
        return tuple(neighbors[best_idx])

    def _fallback(self, neighbors, frontiers, nodes, robot_pos):
        # Move toward nearest unvisited node
        best_j = None
        best_d = float('inf')
        for j, n in enumerate(nodes):
            if not n.get('visited', False):
                d = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) - robot_pos
                ))
                if d < best_d:
                    best_d = d
                    best_j = j
        if best_j is not None:
            target = np.array(nodes[best_j]['coords'], dtype=float)
            best_idx = None
            best_d = float('inf')
            for idx, nb in enumerate(neighbors):
                d = float(np.linalg.norm(np.array(nb, dtype=float) - target))
                if d < best_d:
                    best_d = d
                    best_idx = idx
            if best_idx is not None:
                self.prev_pos = robot_pos
                return tuple(neighbors[best_idx])

        # Move toward nearest frontier
        if frontiers:
            target = np.array(frontiers[0], dtype=float)
            best_idx = None
            best_d = float('inf')
            for idx, nb in enumerate(neighbors):
                d = float(np.linalg.norm(np.array(nb, dtype=float) - target))
                if d < best_d:
                    best_d = d
                    best_idx = idx
            if best_idx is not None:
                self.prev_pos = robot_pos
                return tuple(neighbors[best_idx])

        # Last resort: first neighbor
        if neighbors:
            self.prev_pos = robot_pos
            return tuple(neighbors[0])
        return None


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg_path = os.path.join(args.checkpoint, 'planner_cfg.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path, 'r') as f:
            cfg = json.load(f)
    planner = SimpleGreedyPlanner(**cfg)

    eval_config_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, 'r') as f:
            eval_config = json.load(f)
        if isinstance(eval_config, dict) and 'episodes' in eval_config:
            episodes = eval_config['episodes']
        elif isinstance(eval_config, list):
            episodes = eval_config

    if not episodes:
        maps_dir = os.path.join(args.data_path, 'maps_eval')
        for env_type in ['room', 'tunnel', 'outdoor']:
            d = os.path.join(maps_dir, env_type)
            if not os.path.isdir(d):
                continue
            for fname in sorted(os.listdir(d)):
                if fname.endswith('.png'):
                    episodes.append({
                        'map_path': os.path.join('maps_eval', env_type, fname),
                        'env_type': env_type
                    })

    per_episode = []
    per_type = {
        t: {'explored_rate': [], 'travel_distance': [], 'success': []}
        for t in ['room', 'tunnel', 'outdoor']
    }

    for ep in episodes:
        map_path = os.path.join(args.data_path, ep['map_path'])
        env_type = ep.get('env_type', 'unknown')
        try:
            env = ExplorationEnv(map_path=map_path)
            metrics = run_episode(env, planner)
        except Exception as e:
            print(f'Error on {map_path}: {e}')
            metrics = {
                'explored_rate': 0.0,
                'travel_distance': 0.0,
                'success': False,
                'n_steps': 0
            }

        success = 1 if metrics.get('explored_rate', 0.0) > 0.9999 else 0
        travel_distance = metrics.get('travel_distance', 0.0)
        explored_rate = metrics.get('explored_rate', 0.0)

        per_episode.append({
            'map_path': ep['map_path'],
            'env_type': env_type,
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate
        })
        if env_type in per_type:
            per_type[env_type]['explored_rate'].append(explored_rate)
            per_type[env_type]['travel_distance'].append(travel_distance)
            per_type[env_type]['success'].append(success)

    total_episodes = len(per_episode)
    explored_rate = float(np.mean([e['explored_rate'] for e in per_episode])) if per_episode else 0.0
    success_rate = float(np.mean([e['success'] for e in per_episode])) if per_episode else 0.0
    successful_distances = [e['travel_distance'] for e in per_episode if e['success'] == 1]
    travel_distance = float(np.mean(successful_distances)) if successful_distances else 0.0

    per_type_out = {}
    for t, vals in per_type.items():
        if vals['explored_rate']:
            per_type_out[t] = {
                'explored_rate': float(np.mean(vals['explored_rate'])),
                'travel_distance': float(np.mean(vals['travel_distance'])),
                'success_rate': float(np.mean(vals['success']))
            }
        else:
            per_type_out[t] = {
                'explored_rate': 0.0,
                'travel_distance': 0.0,
                'success_rate': 0.0
            }

    output = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)
    print(
        f'Wrote output for {total_episodes} episodes: '
        f'explored={explored_rate:.4f} success={success_rate:.4f} dist={travel_distance:.1f}'
    )


if __name__ == '__main__':
    main()
